mapper.select:
/* PtnrLinkMapper.getPtnrLinkLstInfo */ SELECT TO_CHAR(A.REGST_DTTM,'YYYYMM') AS baseDate , A.PARTNER_ID AS ptnrId , B.CD_DSC AS ptnrNm , A.FILE_NM AS fileNm , A.SEND_FLAG AS sendFlag , FN_GET_CODENM('CMN0244', A.SEND_FLAG) AS sendFlagNm , A.SEND_RESULT AS sendResult , FN_GET_CODENM('CMN0245', A.SEND_RESULT) AS sendResultNm , TO_CHAR(A.REGST_DTTM,'YYYYMMDD') AS regstDttm , CASE WHEN A.SEND_RESULT = 'S' THEN TO_CHAR(A.RVISN_DTTM,'YYYYMMDD') ELSE '' END AS reusltDate FROM MSP_PARTNER_POINT_FILE A ,CMN_GRP_CD_MST B WHERE A.PARTNER_ID = B.CD_VAL AND B.GRP_ID = 'CMN0073' AND B.USG_YN = 'Y'
AND A.PARTNER_ID = #{ptnrId, jdbcType=VARCHAR}
AND TO_CHAR(A.REGST_DTTM,'YYYYMM') = #{baseDate, jdbcType=VARCHAR}
AND A.SEND_FLAG = #{sendFlag, jdbcType=VARCHAR}
AND A.SEND_RESULT = #{sendResult, jdbcType=VARCHAR}
ORDER BY A.REGST_DTTM DESC

mapper.insert:
/* PtnrLinkMapper.insertPointFile */
INSERT INTO MSP_PARTNER_POINT_FILE
		(
			PARTNER_ID
			, FILE_NM
			, LOCAL_UP_DIR
			, LOCAL_DOWN_DIR
			, HOST_UP_DIR
			, HOST_DOWN_DIR
			, SEND_FLAG
			, SEND_RESULT
			, REGST_ID
			, REGST_DTTM
		) 
		VALUES
		(
			#{partnerId}
			, #{fileNm}
			, #{localUpDir}
			, #{localDownDir}
			, #{hostUpDir}
			, #{hostDownDir}
			, 'R'
			, 'R'
			, 'POINT'
			, SYSDATE
		)

