/* PtnrLinkMapper.updatePointFile */
UPDATE	
		MSP_PARTNER_POINT_FILE
SET
		LOCAL_UP_DIR = #{localUpDir}
		, LOCAL_DOWN_DIR = #{localDownDir}
		, HOST_UP_DIR = #{hostUpDir}
		, HOST_DOWN_DIR = #{hostDownDir}
		, SEND_FLAG = 'R'
		, SEND_RESULT = 'R'
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE 	PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}

