/* PtnrLinkMapper.getPointFileUpList */ SELECT PARTNER_ID AS partnerId , FILE_NM AS fileNm , LOCAL_UP_DIR AS localUpDir , HOST_UP_DIR AS hostUpDir FROM MSP_PARTNER_POINT_FILE WHERE SEND_FLAG <> 'S'
AND PARTNER_ID = #{partnerId}
AND FILE_NM = #{fileNm}

