UPDATE	
		MSP_PARTNER_POINT_FILE
SET
		SEND_FLAG = #{sendFlag}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE 	PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}

mapper.select:
/* PtnrLinkMapper.getPointFileDownList */
SELECT
		PARTNER_ID			AS partnerId
		, DECODE(PARTNER_ID, 'lpoint', REPLACE(FILE_NM, 'O940', 'O941'), FILE_NM) AS fileNm 
		, LOCAL_DOWN_DIR	AS localDownDir
		, HOST_DOWN_DIR		AS hostDownDir
FROM
		MSP_PARTNER_POINT_FILE
WHERE SEND_FLAG = 'S'
/* AND   SEND_RESULT IN ('R', 'F') 상태 관계없이 가져온다. */

	AND PARTNER_ID = #{partnerId}


	AND FILE_NM = #{fileNm}

mapper.update:
/* PtnrLinkMapper.updatePointFileDown */
UPDATE	
		MSP_PARTNER_POINT_FILE
SET
		SEND_RESULT = #{sendResult}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE 	PARTNER_ID = #{partnerId}
AND 	FILE_NM = DECODE(#{partnerId}, 'lpoint', REPLACE(#{fileNm}, 'O941', 'O940'), #{fileNm})

