/* PtnrLinkMapper.updatePartnerJejuair */
UPDATE 
		MSP_PARTNER_JEJUAIR_01
SET 
		RESULT_DTL_CD = #{responseCode}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE BILL_YM = #{billYm}
AND   MEMBER_CI = #{memberCi}

/* PtnrLinkMapper.updateGiftiPointMst */
UPDATE 
		MSP_PARTNER_POINT_MST A
SET 
		PAY_RESULT = #{payResult}
		, RESULT_DTL_CD = #{responseCode}
		, PAY_DTTM = SYSDATE
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE

		, PAY_POINT = REQ_POINT

WHERE A.SEND_FLAG = 'R'
AND   A.FULL_PAY_YN = 'Y'
/* AND   A.PAY_RESULT <> 'S' */
AND   (A.PAY_RESULT IN ('X','F') OR TO_CHAR(A.PAY_DTTM,'YYYYMM') = TO_CHAR(SYSDATE,'YYYYMM'))
AND   A.PARTNER_ID = #{partnerId}
AND   A.CONTRACT_NUM = #{contractNum}

/* PtnrLinkMapper.updatePartnerGifti */
UPDATE 
		MSP_PARTNER_GIFTI_01
SET 
		RESULT_DTL_CD = #{responseCode}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE LINK_YM = #{linkYm}
AND   USG_YM = #{usgYm}
AND   CONTRACT_NUM = #{contractNum}
AND   CTN = #{ctn}

