/* PtnrLinkMapper.updateLPointInterface */
UPDATE  MSP_LPOINT_INTERFACE
SET     RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
        , DATA_63 = #{resCustNo, jdbcType=VARCHAR}
        , DATA_64 = #{resAprvNo, jdbcType=VARCHAR}
        , DATA_65 = #{resAprvDt, jdbcType=VARCHAR}
        , DATA_66 = #{resAprvTm, jdbcType=VARCHAR}
        , DATA_67 = #{resAprvPoint, jdbcType=VARCHAR}
        , DATA_68 = #{resEvntPoint, jdbcType=VARCHAR}
        , DATA_69 = #{resCd, jdbcType=VARCHAR}
        , DATA_70 = #{resMsg, jdbcType=VARCHAR}
WHERE   LINK_YM = #{linkYm, jdbcType=VARCHAR}
AND     TRIM(DATA_07) = #{customerId, jdbcType=VARCHAR}

/* PtnrLinkMapper.updateLPointPointMst */

UPDATE  MSP_PARTNER_POINT_MST A
SET     PAY_RESULT = #{payResult, jdbcType=VARCHAR}
        , RESULT_DTL_CD = #{resCd, jdbcType=VARCHAR}
        , PAY_POINT = DECODE(#{payResult}, 'S', REQ_POINT, PAY_POINT)
        , PAY_DTTM = SYSDATE
        , RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
WHERE A.SEND_FLAG = 'R'
AND   A.FULL_PAY_YN = 'Y'
AND   A.PARTNER_ID = #{partnerId, jdbcType=VARCHAR}
AND   A.CUSTOMER_ID = #{customerId, jdbcType=VARCHAR}
AND   A.PAY_RESULT <> 'S'
AND   A.BILL_YM < #{linkYm, jdbcType=VARCHAR}

/* partnerPointSettleMapper.updatePartnerLPoint */
UPDATE  MSP_PARTNER_LPOINT_01
SET     RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
        , RES_CUST_NO = #{resCustNo, jdbcType=VARCHAR}
        , RES_APRV_NO = #{resAprvNo, jdbcType=VARCHAR}
        , RES_APRV_DT = #{resAprvDt, jdbcType=VARCHAR}
        , RES_CD = #{resCd, jdbcType=VARCHAR}
        , RES_MSG = #{resMsg, jdbcType=VARCHAR}
        , RES_APRV_POINT = #{resAprvPoint, jdbcType=VARCHAR}
WHERE   LINK_YM = #{linkYm, jdbcType=VARCHAR}
AND     CUSTOMER_ID = #{customerId, jdbcType=VARCHAR}
